mapper.select:
UPDATE trip.trips
SET
  itinerary_version = itinerary_version + 1,
  updated_at = #{updatedAt}
WHERE id = #{tripId}
  AND status != 'DELETED'
  AND itinerary_version = #{baseVersion}
RETURNING itinerary_version

SELECT EXISTS (
  SELECT 1
  FROM itinerary.itinerary_days
  WHERE trip_id = #{tripId}
    AND id = #{dayId}
)

SELECT count(*)
FROM itinerary.itinerary_days
WHERE trip_id = #{tripId}

SELECT EXISTS (
  SELECT 1
  FROM itinerary.itinerary_items
  WHERE trip_id = #{tripId}
    AND id = #{itemId}
    AND deleted_at IS NULL
)

mapper.update:
UPDATE itinerary.itinerary_days
SET
  sort_order = #{update.sortOrder},
  updated_at = #{update.updatedAt}
WHERE trip_id = #{update.tripId}
  AND id = #{update.dayId}

UPDATE itinerary.itinerary_items
SET
  itinerary_day_id = #{update.dayId},
  sort_order = #{update.sortOrder},
  updated_by_user_id = #{update.updatedByUserId},
  updated_at = #{update.updatedAt}
WHERE trip_id = #{update.tripId}
  AND id = #{update.itemId}
  AND deleted_at IS NULL
